mapper.select:
SELECT B1.* FROM ( SELECT A1.*, ROW_NUMBER() OVER ( ORDER BY
A1.insertDt DESC
CAST(A1.${sortColumn} AS INTEGER) ${order}
A1.${sortColumn} ${order}
) AS PAGEINDEX FROM ( SELECT info.businessAreaCd, info.businessTypeCd, info.objectNo, info.objectId, info.revNo, info.objectNm, info.objectType, info.objectClassCd2, info.objectClassNm2, info.insertUid, info.updateUid, info.insertDt, info.updateDt, info.interfaceDt, info.insertUserNm, info.registerUser, info.updateUserNm, info.totalPageCnt, info.fileViewNm, info.filePath, info.fileNm, info.checkSum, info.orgFileNm, info.productNm, info.productNo, info.callId, info.applyHogiNo, info.securityTypeCd, info.securityTypeNm, info.fileNo, info.businessTypeNm, info.currentPageNo, info.totalPageNo, info.distributionPoint, info.createDt, info.drawingNo, info.drawingNm, info.changeActionNo, info.factoryRegion , info.customerRevision, info.fileOrder , info.documentPage , info.documentTotalPage, info.drawingUsage , info.documentValidationExpireDate, info.requestedDate , info.documentApprovalDate , info.standardizationApprovalDate , info.technologyChangeApprovalDate , info.modelCode , info.check3DFile, info.inputDate, info.revision , info.connectionId, info.mrbDate, info.approver, info.reviewerUser, info.processingStatus, info.status, info.status AS statusNm, info.status AS statusCd FROM (
SELECT info.BUSINESS_AREA_CD AS businessAreaCd, info.BUSINESS_TYPE_CD AS businessTypeCd, info.BUSINESS_TYPE_NM AS businessTypeNm, info.DOCUMENT_NO AS objectNo, info.OBJECT_ID AS objectId, info.CURRENT_PAGE_NO AS currentPageNo, info.TOTAL_PAGE_NO AS totalPageNo, info.REV_NO AS revNo, info.DOCUMENT_NM AS objectNm, 'DOC' AS objectType, info.DOC_CLASS_CD2 AS objectClassCd2, FN_GET_CD_NM('objectClassCd2', info.DOC_CLASS_CD2, #{sessionLang}) AS objectClassNm2, info.INSERT_UID AS insertUid, info.UPDATE_UID AS updateUid, info.INSERT_DT AS insertDt, info.CREATE_DATE AS createDt, info.mrbDate AS mrbDate, info.APPROVER AS approver, info.REVIEWERUSER AS reviewerUser, COALESCE(fileInfo.PROCESSING_STATUS, '') AS processingStatus, CASE WHEN info.STATUS = '승인완료' THEN '승인완료' WHEN COALESCE(NULLIF(TRIM(info.APPROVER), ''), '') <> '' AND NOT EXISTS ( SELECT 1 FROM regexp_split_to_table(REPLACE(info.APPROVER, ' ', ''), ',') AS ap(token) WHERE ap.token <> '' AND POSITION(',' || ap.token || ',' IN ',' || REPLACE(COALESCE(info.APPROVED_USERS, info.STATUS, ''), ' ', '') || ',') = 0 ) AND ( COALESCE(NULLIF(TRIM(info.REVIEWERUSER), ''), '') = '' OR NOT EXISTS ( SELECT 1 FROM regexp_split_to_table(REPLACE(info.REVIEWERUSER, ' ', ''), ',') AS rv(token) WHERE rv.token <> '' AND POSITION(',' || rv.token || ',' IN ',' || REPLACE(COALESCE(info.APPROVED_USERS, info.STATUS, ''), ' ', '') || ',') = 0 ) ) THEN '승인완료' ELSE '승인진행중' END AS status, info.UPDATE_DT AS updateDt, info.INTERFACE_DT AS interfaceDt, (SELECT USER_NM FROM DOCS_USER tmp WHERE tmp.USER_ID = info.INSERT_UID) AS insertUserNm, info.REGISTER_USER AS registerUser, (SELECT USER_NM FROM DOCS_USER tmp WHERE tmp.USER_ID = info.UPDATE_UID) AS updateUserNm, info.TOTAL_PAGE_CNT AS totalPageCnt, COALESCE(info.APPLY_PRODUCT_NO, '') AS productNm, info.APPLY_PRODUCT_NO AS productNo, info.CALL_ID AS callId, info.APPLY_HOGI_NO AS applyHogiNo, info.SECURITY_TYPE_CD AS securityTypeCd, FN_GET_CD_NM('securityTypeCd', info.SECURITY_TYPE_CD, #{sessionLang}) AS securityTypeNm, DENSE_RANK() OVER (PARTITION BY info.DOCUMENT_NO ORDER BY info.REV_NO DESC) AS rnk, fileInfo.FILE_NO AS fileNo, fileInfo.ORG_FILE_NM AS fileViewNm, fileInfo.FILE_NM AS fileNm, fileInfo.FILE_SIZE AS fileSize, fileInfo.ORG_FILE_NM AS orgFileNm, fileInfo.FILE_PATH_NM AS filePath, info.DISTRIBUTION_POINT AS distributionPoint, info.drawing_no AS drawingNo, info.drawing_nm AS drawingNm, info.change_action_no AS changeActionNo, '창원' AS factoryRegion, info.customer_revision AS customerRevision, info.file_order AS fileOrder, info.document_page AS documentPage, info.document_total_page AS documentTotalPage, info.drawing_usage AS drawingUsage, info.document_validation_expiredate AS documentValidationExpireDate, info.request_ed_date AS requestedDate, info.document_approval_date AS documentApprovalDate, info.standardization_approval_date AS standardizationApprovalDate, info.technology_change_approval_date AS technologyChangeApprovalDate, info.model_code AS modelCode, info.check_3dfile AS check3DFile, info.input_date AS inputDate, info.revision AS revision, info.connection_id AS connectionId, '' AS checkSum, ROW_NUMBER() OVER ( PARTITION BY COALESCE(info.DRAWING_NO, info.DOCUMENT_NO, info.OBJECT_ID) ORDER BY info.CREATE_DATE DESC ) AS rn FROM DOCS_PRODUCT_DOCUMENT_FILE fileInfo JOIN DOCS_PRODUCT_DOCUMENT info ON fileInfo.OBJECT_ID = info.OBJECT_ID
WHERE DENSE_RANK() OVER (PARTITION BY DOCUMENT_NO ORDER BY CUSTOMER_REVISION DESC) = 1
AND info.DRAWING_NO = UPPER(TRIM(#{drawingNo}))
AND info.DRAWING_NO LIKE '%' || UPPER(TRIM(#{drawingNo})) || '%'
SELECT info.BUSINESS_AREA_CD AS businessAreaCd, info.BUSINESS_TYPE_CD AS businessTypeCd, info.DOCUMENT_NO AS objectNo, info.CURRENT_PAGE_NO AS currentPageNo, info.TOTAL_PAGE_NO AS totalPageNo, info.OBJECT_ID AS objectId, info.REV_NO AS revNo, info.DOCUMENT_NM AS objectNm, 'DOC' AS objectType, DOC_CLASS_CD2 AS objectClassCd2, FN_GET_CD_NM('objectClassCd2', DOC_CLASS_CD2, #{sessionLang}) AS objectClassNm2, info.INSERT_UID AS insertUid, info.UPDATE_UID AS updateUid, info.INSERT_DT AS insertDt, info.CREATE_DATE AS createDt, info.mrbDate AS mrbDate, info.APPROVER AS approver, info.REVIEWERUSER AS reviewerUser, COALESCE(fileInfo.PROCESSING_STATUS, '') AS processingStatus, CASE WHEN info.STATUS = '승인완료' THEN '승인완료' WHEN COALESCE(NULLIF(TRIM(info.APPROVER), ''), '') <> '' AND NOT EXISTS ( SELECT 1 FROM regexp_split_to_table(REPLACE(info.APPROVER, ' ', ''), ',') AS ap(token) WHERE ap.token <> '' AND POSITION(',' || ap.token || ',' IN ',' || REPLACE(COALESCE(info.APPROVED_USERS, info.STATUS, ''), ' ', '') || ',') = 0 ) AND ( COALESCE(NULLIF(TRIM(info.REVIEWERUSER), ''), '') = '' OR NOT EXISTS ( SELECT 1 FROM regexp_split_to_table(REPLACE(info.REVIEWERUSER, ' ', ''), ',') AS rv(token) WHERE rv.token <> '' AND POSITION(',' || rv.token || ',' IN ',' || REPLACE(COALESCE(info.APPROVED_USERS, info.STATUS, ''), ' ', '') || ',') = 0 ) ) THEN '승인완료' ELSE '승인진행중' END AS status, info.UPDATE_DT AS updateDt, info.INTERFACE_DT AS interfaceDt, (SELECT USER_NM FROM DOCS_USER tmp WHERE tmp.USER_ID = info.INSERT_UID) AS insertUserNm, info.REGISTER_USER AS registerUser, (SELECT USER_NM FROM DOCS_USER tmp WHERE tmp.USER_ID = info.UPDATE_UID) AS updateUserNm, TOTAL_PAGE_CNT AS totalPageCnt, COALESCE(info.APPLY_PRODUCT_NO, '') AS productNm, info.APPLY_PRODUCT_NO AS productNo, CALL_ID AS callId, info.APPLY_HOGI_NO AS applyHogiNo, info.SECURITY_TYPE_CD AS securityTypeCd, FN_GET_CD_NM('securityTypeCd', info.SECURITY_TYPE_CD, #{sessionLang}) AS securityTypeNm, fileInfo.FILE_NO AS fileNo, fileInfo.ORG_FILE_NM AS fileViewNm, fileInfo.FILE_NM AS fileNm, fileInfo.FILE_SIZE AS fileSize, fileInfo.ORG_FILE_NM AS orgFileNm, fileInfo.FILE_PATH_NM AS filePath, info.DISTRIBUTION_POINT AS distributionPoint, '' AS checkSum, ROW_NUMBER() OVER ( PARTITION BY info.DRAWING_NO ORDER BY info.CREATE_DATE DESC ) AS rn FROM DOCS_PRODUCT_DOCUMENT_FILE fileInfo JOIN DOCS_PRODUCT_DOCUMENT info ON fileInfo.OBJECT_ID = info.OBJECT_ID
WHERE 1=1 AND info.DELETED_YN = 'N'
AND EXISTS ( SELECT 1 FROM DOCS_PRODUCT_TREE node JOIN DOCS_PRODUCT_TREE selectedNode ON selectedNode.TREE_CD = #{treeCd} WHERE node.TREE_CD = info.TREE_CD AND node.TREE_PATH LIKE selectedNode.TREE_PATH || '%' )
AND ( COALESCE(info.DISTRIBUTION_POINT, '') = '' OR POSITION(',' || #{deptNm} || ',' IN ',' || info.DISTRIBUTION_POINT || ',') > 0 )
AND DOCUMENT_NO LIKE '%' || UPPER(TRIM(#{objectNo})) || '%'
AND info.DRAWING_NO = UPPER(TRIM(#{drawingNo}))
AND info.DRAWING_NO LIKE '%' || UPPER(TRIM(#{drawingNo})) || '%'
AND info.DOCUMENT_NM LIKE '%' || #{objectNm} || '%'
AND INSERT_UID = #{insertUid}
AND INSERT_DEPT_NM LIKE #{insertDeptNm}
AND DOC_CLASS_CD2 LIKE #{objectClassCd2}
AND info.INTERFACE_DT BETWEEN TO_DATE(#{interfaceStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{interfaceEndDt}, 'YYYY-MM-DD') + INTERVAL '1 DAY'
AND (
(DOCUMENT_NO LIKE '%' || UPPER(TRIM(#{productionInfo.objectNo})) || '%')
)
AND (
(DOCUMENT_NO = UPPER(TRIM(#{productionInfo.objectNo})))
)
) info ) A1 ) B1 WHERE 1=1
AND PAGEINDEX <= #{end}
AND PAGEINDEX >= #{start}

mapper.insert:
INSERT INTO DOCS_REQUEST_DETAIL
(REQUEST_NO, PROCESS_SEQ, APPROVAL_STATUS_CD, ORIGINAL_USER_CD, ACTUAL_USER_CD, REQUEST_DESC, ACTION_DT, ACTION_CD, APPROVAL_GRADE_CD)
SELECT #{requestNo} AS REQUEST_NO,
	   PROCESS_SEQ_NO AS PROCESS_SEQ,
	   APPROVAL_STATUS_CD,
	   CASE WHEN APPROVAL_STATUS_CD = 'REQUEST' THEN #{sessionUser.userCd}
			WHEN APPROVAL_STATUS_CD = 'APPROVAL' THEN #{sessionUser.teamLeaderUid}
			ELSE '' END AS ORIGINAL_USER_CD,
	   CASE WHEN APPROVAL_STATUS_CD = 'REQUEST' THEN #{sessionUser.userCd}
			WHEN APPROVAL_STATUS_CD = 'APPROVAL' THEN #{teamLeader}
			ELSE '' END AS ACTUAL_USER_CD,
	   CASE WHEN APPROVAL_STATUS_CD = 'REQUEST' THEN #{requestDesc}
			ELSE NULL END AS REQUEST_DESC,
	   CASE WHEN APPROVAL_STATUS_CD = 'REQUEST' THEN NOW()
			ELSE NULL END AS ACTION_DT,
	   'REQUEST' AS ACTION_CD,
	   CASE WHEN APPROVAL_LINE_ID = 6 AND PROCESS_SEQ_NO = 2 THEN 'TL'
			ELSE '' END AS APPROVAL_GRADE_CD
FROM DOCS_APPROVAL_LINE_DETAIL
WHERE APPROVAL_LINE_ID = #{approvalLineId}

mapper.select:
SELECT OBJECT_ID
FROM DOCS_PRODUCT_DOCUMENT_FILE
WHERE OBJECT_ID = #{objectId}

mapper.update:
UPDATE DOCS_PRODUCT_DOCUMENT
SET DELETED_YN = 'Y' 
WHERE OBJECT_ID = #{objectId}

mapper.select:
SELECT mainFile.OBJECT_ID AS "objectId", CAST(mainFile.FILE_NO AS TEXT) AS "fileNo", mainFile.ORG_FILE_NM AS "orgFileNm", mainFile.FILE_PATH_NM AS "filePath" FROM DOCS_PRODUCT_DOCUMENT_FILE mainFile JOIN DOCS_PRODUCT_DOCUMENT doc ON doc.OBJECT_ID = mainFile.OBJECT_ID WHERE mainFile.OBJECT_ID = #{objectId} AND COALESCE(doc.DELETED_YN, 'N') = 'N' AND CAST(mainFile.FILE_NO AS INTEGER) = 1
AND CAST(mainFile.FILE_NO AS TEXT) = #{fileNo}
UNION ALL SELECT subFile.OBJECT_ID AS "objectId", CAST(subFile.FILE_NO AS TEXT) AS "fileNo", subFile.ORG_FILE_NM AS "orgFileNm", subFile.FILE_PATH_NM AS "filePath" FROM DOCS_PRODUCTION_SUB_FILE subFile WHERE subFile.OBJECT_ID = #{objectId} AND COALESCE(subFile.USE_YN, 'Y') = 'Y'
AND CAST(subFile.FILE_NO AS TEXT) = #{fileNo}
LIMIT 1
